using System.Collections;
using System.Collections.Generic;
using UnityEngine;

public class TerrainGenerator : MonoBehaviour
{
    public int chunkSize = 16;
    public int octaves = 3;
    public float scale = 50f;
    public float heightMultiplier = 40f;
    public Texture[] textures;

    void Start()
    {
        GenerateTerrain(new Vector3(0, 0, 0));
        GenerateTerrain(new Vector3(chunkSize, 0, 0));
        GenerateTerrain(new Vector3(0, 0, chunkSize));
        GenerateTerrain(new Vector3(chunkSize, 0, chunkSize));
    }

    void GenerateTerrain(Vector3 position)
    {
        float[,] noiseMap = new float[chunkSize, chunkSize];

        for (int x = 0; x < chunkSize; x++) {
            for (int y = 0; y < chunkSize; y++) {
                float amplitude = 1f;
                float frequency = 1f;
                float noiseHeight = 0f;

                for (int i = 0; i < octaves; i++) {
                    float xCoord = (position.x + x) / scale * frequency;
                    float yCoord = (position.z + y) / scale * frequency;
                    float noiseValue = Mathf.PerlinNoise(xCoord, yCoord) * 2f - 1f;

                    noiseHeight += noiseValue * amplitude;

                    amplitude *= 0.5f;
                    frequency *= 2f;
                }

                noiseMap[x, y] = noiseHeight * heightMultiplier;
            }
        }

        for (int x = 0; x < chunkSize; x++) {
            for (int y = 0; y < chunkSize; y++) {
                int blockHeight = (int)noiseMap[x, y];
                for (int z = 0; z < blockHeight; z++) {
                    GameObject block = new GameObject("Terrain Block");
                    block.transform.position = new Vector3(x + position.x, z, y + position.z);

                    if (z == blockHeight - 1) {
                        block.AddComponent<MeshFilter>().mesh = CreateCubeMesh();
                        block.AddComponent<MeshRenderer>().material = new Material(Shader.Find("Standard"));
                        block.GetComponent<MeshRenderer>().material.mainTexture = textures[0];
                    } else if (z >= blockHeight - 4) {
                        block.AddComponent<MeshFilter>().mesh = CreateCubeMesh();
                        block.AddComponent<MeshRenderer>().material = new Material(Shader.Find("Standard"));
                        block.GetComponent<MeshRenderer>().material.mainTexture = textures[1];
                    } else {
                        block.AddComponent<MeshFilter>().mesh = CreateCubeMesh();
                        block.AddComponent<MeshRenderer>().material = new Material(Shader.Find("Standard"));
                        block.GetComponent<MeshRenderer>().material.mainTexture = textures[2];
                    }
                }
            }
        }
    }

    Mesh CreateCubeMesh()
    {
